SELECT
    pho.id AS "id",
    pho.register_id AS "registerId",
    pho.observed_at::date AS "recordDate",
    pho.observed_at AS "recordedAt",
    pho.metric_code AS "metricKey",
    pho.metric_value AS "metricValue",
    pho.unit AS "unit",
    pho.source_type AS "source",
    pho.note AS "note"
FROM patient_health_observation pho
WHERE pho.register_id = #{registerId}

    AND pho.observed_at::date >= #{from}


    AND pho.observed_at::date <= #{to}


    AND pho.metric_code IN

        #{key}



    AND pho.source_type = #{sourceType}


    AND pho.source_type IN

        #{st}


ORDER BY pho.observed_at ASC, pho.metric_code ASC
